_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret=0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//vUv = ((vUv-0.5)+vec2(0,0.02))*0.96+0.5;
uv1 = vec2 (vUv.x-0.5, ym-vUv.y)*fov;
dist=GetPixel(vUv).b;
mask=GetPixel(vUv).r>0.02;
struc=GetPixel(vUv)*mask;
ey=1-(vUv.y-ym)*dist*fov*z0;

if (uv1.y>0) { p=z0*uv1.x;  q=z0*uv1.y+M_PI/2+z0-1;} //hinten
else if (uv1.y<-1/(z0-1)) { q=-1/uv1.y*1; p=uv1.x*q;} //vorn
else
  { a=-(1+uv1.y); b=2*uv1.y; c= 1+uv1.y*(z0-1);
    float bet=(b+sqrt(b*b-4*a*c))/(2*a); alp=bet*-(M_PI/2);
    q=alp-1+z0; p=uv1.x * (z0+sin(alp)-1);}
uv3 = vec2(p,q);

ret = sat(16*abs(fract(p/wid+0.5)-0.5))/4;
str = int(p/wid);
smask=(str<slots)*(str>-slots);
ret *= smask;

vec2 ka=texture(pnl,uv3/wid/256);
ret *= (1+1*noise2(uv3*ka.y).x)*scol(str);

pro=noise2(uv3*ka.y).x-noise2(uv3*ka.y+0.001);
bli=pow((1-vUv.x+pro.x*!mask),7);
ret*=(1+GetBlur1((vUv+pro*0.05)).g*10); //shadows
ret *= 0.2+bli ;

k1=1+(1/dist);
h = vec2 (k1,0)*uTexSize.zw;
v = vec2 (0,k1)*uTexSize.zw;

dz.x = getr (vUv+h) - getr (vUv-h);
dz.y = getr (vUv+v) - getr (vUv-v);
dz *= mask*0.3;

//streifenbeleuchtung
s=(p/fov/z0+0.5) ;
uv4=fract(vec2(s+dz.x*-.02*(1+ey),wid/fov/z0/2));
fl = mix(GetBlur1(uv4),GetBlur1(uv4),!mask).g*1.5;

//#######################################################
uv4=fract(vec2(s,0)+vec2(0,wid/fov/z0/2));
float bb=GetPixel(uv4).b;
float ll=(4*pow(sin(q10*8-0.5*vUv.x*M_PI),1114));
fl += sat(1-pow(q-7,2)*(3*bb)+2*pro) * bb * (1+0*ll) * !mask;

ret += fl*sat(0.5+q/z0)*scol(str);

ball=dz.y/3;

bcol=scol(+p/wid*sat(1-ey*(1-dist)));
refl=(sat(-dz.y)*(0.5+4*fl))*bcol;
ball+=refl*sat(1-ey*0.);

//lichtreflektion
ball += lum(GetBlur1(fract(vUv-dz*0.7)))*mask*bcol;
k1=2+(1-dist)*6;
h = vec2 (k1,0)*uTexSize.zw;
v = vec2 (0,k1)*uTexSize.zw;

dz2.x = getr1 (vUv+h) - getr1 (vUv-h);
dz2.y = getr1 (vUv+v) - getr1 (vUv-v);
ball += 0.03/length(dz2-0.2*vUv)*struc*(1+bcol);
ball *= 1-dist/3;

k1 = 0.1/length(cos(42*vUv*vec2(1,0.08)+vec2((vUv.y)*3*uv1.x,0)));
ret = mix(ret,k1* (2+spa(vUv,q11*(floor(k1*32)/4)))*(.5+scol(p/wid)),!smask);

ret = mix(ret,ball,mask);
//ret = GetPixel(vUv);

  fragColor = ret;
}
